document.addEventListener("DOMContentLoaded",function(){const distanciaInput=document.getElementById("distancia");const tempoInput=document.getElementById("tempo");const ritmoInput=document.getElementById("ritmo");const distanciaBtns=document.querySelectorAll(".distancia-btn");const vdotValue=document.getElementById("vdot-value");const vdotClassification=document.getElementById("vdot-classification");const vdotDescription=document.getElementById("vdot-description");const paceRecovery=document.getElementById("pace-recovery");const paceEasy=document.getElementById("pace-easy");const paceMarathon=document.getElementById("pace-marathon");const paceThreshold=document.getElementById("pace-threshold");const paceInterval=document.getElementById("pace-interval");const paceRepetition=document.getElementById("pace-repetition");const time5k=document.getElementById("time-5k");const time10k=document.getElementById("time-10k");const timeHalf=document.getElementById("time-half");const timeFull=document.getElementById("time-full");let ultimoCampoEditado=null;let calculando=false;distanciaBtns.forEach(btn=>{btn.addEventListener("click",function(){distanciaBtns.forEach(b=>b.classList.remove("active"));this.classList.add("active");distanciaInput.value=this.dataset.value;ultimoCampoEditado="distancia";calcularVDOT()})});distanciaInput.addEventListener("input",function(){ultimoCampoEditado="distancia";calcularVDOT()});tempoInput.addEventListener("input",function(){ultimoCampoEditado="tempo";calcularVDOT()});ritmoInput.addEventListener("input",function(){ultimoCampoEditado="ritmo";calcularVDOT()});tempoInput.addEventListener("blur",function(){this.value=formatarTempoInput(this.value)});ritmoInput.addEventListener("blur",function(){this.value=formatarRitmoInput(this.value)});function calcularVDOT(){if(calculando)return;calculando=true;try{const distancia=parseFloat(distanciaInput.value)||0;if(ultimoCampoEditado==="tempo"||ultimoCampoEditado==="distancia"){const tempoSegundos=converterTempoParaSegundos(tempoInput.value);if(distancia>0&&tempoSegundos>0){const ritmoSegundos=tempoSegundos/distancia;ritmoInput.value=formatarSegundosParaRitmo(ritmoSegundos);const vdot=calcularVDOTDeTempo(distancia,tempoSegundos);atualizarResultados(vdot)}}else if(ultimoCampoEditado==="ritmo"){const ritmoSegundos=converterRitmoParaSegundos(ritmoInput.value);if(distancia>0&&ritmoSegundos>0){const tempoSegundos=ritmoSegundos*distancia;tempoInput.value=formatarSegundosParaTempo(tempoSegundos);const vdot=calcularVDOTDeTempo(distancia,tempoSegundos);atualizarResultados(vdot)}}}catch(error){console.error("Erro no cálculo:",error)}calculando=false}function calcularVDOTDeTempo(distancia,tempoSegundos){const velocidade=distancia*1e3/tempoSegundos;let vdot;if(distancia===5){if(tempoSegundos<900)vdot=80;else if(tempoSegundos<960)vdot=75;else if(tempoSegundos<1020)vdot=70;else if(tempoSegundos<1080)vdot=65;else if(tempoSegundos<1140)vdot=60;else if(tempoSegundos<1200)vdot=55;else if(tempoSegundos<1260)vdot=50;else if(tempoSegundos<1320)vdot=45;else if(tempoSegundos<1380)vdot=40;else if(tempoSegundos<1440)vdot=35;else if(tempoSegundos<1500)vdot=30;else vdot=25}else if(distancia===10){if(tempoSegundos<1860)vdot=80;else if(tempoSegundos<1980)vdot=75;else if(tempoSegundos<2100)vdot=70;else if(tempoSegundos<2220)vdot=65;else if(tempoSegundos<2340)vdot=60;else if(tempoSegundos<2460)vdot=55;else if(tempoSegundos<2580)vdot=50;else if(tempoSegundos<2700)vdot=45;else if(tempoSegundos<2820)vdot=40;else if(tempoSegundos<2940)vdot=35;else if(tempoSegundos<3060)vdot=30;else vdot=25}else if(Math.abs(distancia-21.1)<.1){if(tempoSegundos<3960)vdot=80;else if(tempoSegundos<4200)vdot=75;else if(tempoSegundos<4440)vdot=70;else if(tempoSegundos<4680)vdot=65;else if(tempoSegundos<4920)vdot=60;else if(tempoSegundos<5160)vdot=55;else if(tempoSegundos<5400)vdot=50;else if(tempoSegundos<5640)vdot=45;else if(tempoSegundos<5880)vdot=40;else if(tempoSegundos<6120)vdot=35;else if(tempoSegundos<6360)vdot=30;else vdot=25}else if(Math.abs(distancia-42.2)<.1){if(tempoSegundos<8100)vdot=80;else if(tempoSegundos<8700)vdot=75;else if(tempoSegundos<9300)vdot=70;else if(tempoSegundos<9900)vdot=65;else if(tempoSegundos<10500)vdot=60;else if(tempoSegundos<11100)vdot=55;else if(tempoSegundos<11700)vdot=50;else if(tempoSegundos<12300)vdot=45;else if(tempoSegundos<12900)vdot=40;else if(tempoSegundos<13500)vdot=35;else if(tempoSegundos<14100)vdot=30;else vdot=25}else{if(velocidade>5.5)vdot=80;else if(velocidade>5.2)vdot=75;else if(velocidade>4.9)vdot=70;else if(velocidade>4.6)vdot=65;else if(velocidade>4.3)vdot=60;else if(velocidade>4)vdot=55;else if(velocidade>3.7)vdot=50;else if(velocidade>3.4)vdot=45;else if(velocidade>3.1)vdot=40;else if(velocidade>2.8)vdot=35;else if(velocidade>2.5)vdot=30;else vdot=25}return vdot}function atualizarResultados(vdot){vdotValue.textContent=vdot;atualizarClassificacao(vdot);atualizarRitmos(vdot);atualizarTemposPrevistos(vdot)}function atualizarClassificacao(vdot){let classificacao,descricao;vdotClassification.classList.remove("poor","fair","good","excellent","superior");if(vdot<30){classificacao="Fraco";descricao="Fraco (< 30 ml/kg/min): Condição física abaixo da média, típica de iniciantes ou pessoas sedentárias.";vdotClassification.classList.add("poor")}else if(vdot<40){classificacao="Regular";descricao="Regular (30-39 ml/kg/min): Condição física média, típica de pessoas moderadamente ativas.";vdotClassification.classList.add("fair")}else if(vdot<55){classificacao="Bom";descricao="Bom (40-54 ml/kg/min): Boa condição física, típica de corredores regulares e praticantes de esportes.";vdotClassification.classList.add("good")}else if(vdot<70){classificacao="Excelente";descricao="Excelente (55-69 ml/kg/min): Condição física superior, típica de corredores competitivos e atletas treinados.";vdotClassification.classList.add("excellent")}else{classificacao="Superior";descricao="Superior (≥ 70 ml/kg/min): Condição física excepcional, típica de atletas de elite e corredores profissionais.";vdotClassification.classList.add("superior")}vdotClassification.textContent=classificacao;vdotDescription.textContent=descricao}function atualizarRitmos(vdot){const recoveryPaceMin=calcularRitmoPorVDOT(vdot,.65);const recoveryPaceMax=calcularRitmoPorVDOT(vdot,.75);paceRecovery.textContent=`${formatarSegundosParaRitmo(recoveryPaceMin)}-${formatarSegundosParaRitmo(recoveryPaceMax)}/km`;const easyPaceMin=calcularRitmoPorVDOT(vdot,.75);const easyPaceMax=calcularRitmoPorVDOT(vdot,.85);paceEasy.textContent=`${formatarSegundosParaRitmo(easyPaceMin)}-${formatarSegundosParaRitmo(easyPaceMax)}/km`;const marathonPace=calcularRitmoPorVDOT(vdot,.85);paceMarathon.textContent=`${formatarSegundosParaRitmo(marathonPace)}/km`;const thresholdPace=calcularRitmoPorVDOT(vdot,1);paceThreshold.textContent=`${formatarSegundosParaRitmo(thresholdPace)}/km`;const intervalPace=calcularRitmoPorVDOT(vdot,1.12);paceInterval.textContent=`${formatarSegundosParaRitmo(intervalPace)}/km`;const repetitionPace=calcularRitmoPorVDOT(vdot,1.3);paceRepetition.textContent=`${formatarSegundosParaRitmo(repetitionPace)}/km`}function calcularRitmoPorVDOT(vdot,percentualLimiar){const ritmosPorVDOT={30:360,35:330,40:300,45:280,50:260,55:245,60:230,65:220,70:210,75:200,80:190};const vdotKeys=Object.keys(ritmosPorVDOT).map(Number);let lowerKey=vdotKeys[0];let upperKey=vdotKeys[vdotKeys.length-1];for(let i=0;i<vdotKeys.length;i++){if(vdotKeys[i]<=vdot&&vdotKeys[i]>lowerKey){lowerKey=vdotKeys[i]}if(vdotKeys[i]>=vdot&&vdotKeys[i]<upperKey){upperKey=vdotKeys[i]}}let ritmoLimiar;if(lowerKey===upperKey){ritmoLimiar=ritmosPorVDOT[lowerKey]}else{const ratio=(vdot-lowerKey)/(upperKey-lowerKey);ritmoLimiar=ritmosPorVDOT[lowerKey]-ratio*(ritmosPorVDOT[lowerKey]-ritmosPorVDOT[upperKey])}return ritmoLimiar/percentualLimiar}function atualizarTemposPrevistos(vdot){const tempo5k=calcularTempoPrevisto(5,vdot);const tempo10k=calcularTempoPrevisto(10,vdot);const tempoMeia=calcularTempoPrevisto(21.1,vdot);const tempoMaratona=calcularTempoPrevisto(42.2,vdot);time5k.textContent=formatarSegundosParaTempo(tempo5k);time10k.textContent=formatarSegundosParaTempo(tempo10k);timeHalf.textContent=formatarSegundosParaTempo(tempoMeia);timeFull.textContent=formatarSegundosParaTempo(tempoMaratona)}function calcularTempoPrevisto(distancia,vdot){let ritmoSegundos;if(distancia===5){ritmoSegundos=calcularRitmoPorVDOT(vdot,1.07)}else if(distancia===10){ritmoSegundos=calcularRitmoPorVDOT(vdot,1.03)}else if(Math.abs(distancia-21.1)<.1){ritmoSegundos=calcularRitmoPorVDOT(vdot,.97)}else if(Math.abs(distancia-42.2)<.1){ritmoSegundos=calcularRitmoPorVDOT(vdot,.87)}else{ritmoSegundos=calcularRitmoPorVDOT(vdot,1)}return ritmoSegundos*distancia}function converterTempoParaSegundos(tempo){if(!tempo)return 0;const partes=tempo.split(":");let segundos=0;if(partes.length===3){segundos=parseInt(partes[0])*3600+parseInt(partes[1])*60+parseInt(partes[2])}else if(partes.length===2){segundos=parseInt(partes[0])*60+parseInt(partes[1])}else{segundos=parseInt(partes[0])}return isNaN(segundos)?0:segundos}function converterRitmoParaSegundos(ritmo){if(!ritmo)return 0;const partes=ritmo.split(":");let segundos=0;if(partes.length===2){segundos=parseInt(partes[0])*60+parseInt(partes[1])}else{segundos=parseInt(partes[0])}return isNaN(segundos)?0:segundos}function formatarSegundosParaTempo(segundos){if(!segundos)return"00:00:00";const horas=Math.floor(segundos/3600);const minutos=Math.floor(segundos%3600/60);const segs=Math.floor(segundos%60);return`${String(horas).padStart(2,"0")}:${String(minutos).padStart(2,"0")}:${String(segs).padStart(2,"0")}`}function formatarSegundosParaRitmo(segundos){if(!segundos)return"0:00";const minutos=Math.floor(segundos/60);const segs=Math.floor(segundos%60);return`${minutos}:${String(segs).padStart(2,"0")}`}function formatarTempoInput(valor){if(!valor)return"";valor=valor.replace(/[^\d:]/g,"");const partes=valor.split(":");if(partes.length===3){const horas=parseInt(partes[0])||0;const minutos=parseInt(partes[1])||0;const segundos=parseInt(partes[2])||0;return`${String(horas).padStart(2,"0")}:${String(minutos).padStart(2,"0")}:${String(segundos).padStart(2,"0")}`}else if(partes.length===2){const minutos=parseInt(partes[0])||0;const segundos=parseInt(partes[1])||0;if(minutos>59){const horas=Math.floor(minutos/60);const mins=minutos%60;return`${String(horas).padStart(2,"0")}:${String(mins).padStart(2,"0")}:${String(segundos).padStart(2,"0")}`}return`00:${String(minutos).padStart(2,"0")}:${String(segundos).padStart(2,"0")}`}else{const segundos=parseInt(partes[0])||0;if(segundos>59){const minutos=Math.floor(segundos/60);const segs=segundos%60;if(minutos>59){const horas=Math.floor(minutos/60);const mins=minutos%60;return`${String(horas).padStart(2,"0")}:${String(mins).padStart(2,"0")}:${String(segs).padStart(2,"0")}`}return`00:${String(minutos).padStart(2,"0")}:${String(segs).padStart(2,"0")}`}return`00:00:${String(segundos).padStart(2,"0")}`}}function formatarRitmoInput(valor){if(!valor)return"";valor=valor.replace(/[^\d:]/g,"");const partes=valor.split(":");if(partes.length===2){const minutos=parseInt(partes[0])||0;const segundos=parseInt(partes[1])||0;return`${minutos}:${String(segundos).padStart(2,"0")}`}else{const segundos=parseInt(partes[0])||0;if(segundos>59){const minutos=Math.floor(segundos/60);const segs=segundos%60;return`${minutos}:${String(segs).padStart(2,"0")}`}return`0:${String(segundos).padStart(2,"0")}`}}calcularVDOT()});